336	\begin{theorem}
337	\leanok
338	[Generic flatness, algebraic form]
339	  \label{thm:generic_flatness_algebraic}
340	  \lean{AlgebraicGeometry.GenericFreeness.genericFlatnessAlgebraic}
341	  \uses{def:generically_free}
342	  \source{nitsure-hilbert-quot}
343	  \textit{Source: [Nitsure], \S4, ``Lemma on Generic Flatness''.}
344	  Let \(A\) be a noetherian domain, \(B\) a finite-type \(A\)-algebra, and \(M\) a finite
345	  \(B\)-module. Then \(M\) is generically free over \(A\): there exists
346	  \(f \in A\), \(f \ne 0\), such that the localisation
347	  \(M_f\) is a free \(A_f\)-module.
348	\end{theorem}
349	
350	\begin{proof}
351	  \uses{lem:generically_free_subsingleton, lem:generically_free_of_equiv,
352	    lem:generically_free_splice, lem:generically_free_domain_core}
353	  The ring \(B\) is noetherian (it is of finite type over the noetherian
354	  \(A\)), so the finite \(B\)-module \(M\) admits a finite prime filtration
355	  \[
356	    0 = M_0 \subset M_1 \subset \cdots \subset M_r = M
357	  \]
358	  with successive quotients \(M_i / M_{i-1} \cong B / \mathfrak{p}_i\) for
359	  prime ideals \(\mathfrak{p}_i \subset B\).  By induction on the filtration
360	  length it suffices that generic freeness over \(A\) holds for the zero
361	  module (\cref{lem:generically_free_subsingleton}), holds for each quotient
362	  domain \(B/\mathfrak{p}\) (\cref{lem:generically_free_domain_core},
363	  transported along the isomorphism \(M_i/M_{i-1} \cong B/\mathfrak{p}_i\) by
364	  \cref{lem:generically_free_of_equiv}), and is stable under extensions
365	  (the splicing lemma, \cref{lem:generically_free_splice}, applied to
366	  \(0 \to M_{i-1} \to M_i \to M_i/M_{i-1} \to 0\)).
367	\end{proof}
